async function loadHeader(){try{const e=await fetch("/assets/components/header.html"),t=await e.text();document.getElementById("header-placeholder").innerHTML=t;const a=document.querySelectorAll(".header-nav-dropdown");a.forEach(e=>{const t=e.querySelector(".header-header-nav-dropdown-toggle");t.addEventListener("click",t=>{t.preventDefault();const o=e.classList.contains("active");a.forEach(e=>e.classList.remove("active")),o||e.classList.add("active")})}),document.addEventListener("click",e=>{const t=e.target.closest(".header-header-nav-dropdown-menu a");if(t)return void a.forEach(e=>{e.classList.remove("active")});const o=e.target.closest(".header-nav-dropdown");o||a.forEach(e=>{e.classList.remove("active")})}),document.addEventListener("keydown",e=>{"Escape"===e.key&&a.forEach(e=>{e.classList.remove("active")})})}catch(e){console.error("Error loading header:",e)}}document.addEventListener("DOMContentLoaded",loadHeader);